resource apim 'Microsoft.ApiManagement/service@2022-08-01' = {
  name: 'apim-integration-prod'
  location: location
  sku: {
    name: 'Developer'  // Use 'Premium' for VNET/Internal mode in prod
    capacity: 1
  }
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    publisherEmail: 'api-admin@company.com'
    publisherName: 'Company Integration Team'
    virtualNetworkType: 'Internal'  // Internal mode — no public IP
    virtualNetworkConfiguration: {
      subnetResourceId: apimSubnet.id
    }
    customProperties: {
      'Microsoft.WindowsAzure.ApiManagement.Gateway.Security.Protocols.Tls10': 'false'
      'Microsoft.WindowsAzure.ApiManagement.Gateway.Security.Protocols.Tls11': 'false'
      'Microsoft.WindowsAzure.ApiManagement.Gateway.Security.Backend.Protocols.Ssl30': 'false'
    }
  }
}

// Link Application Insights
resource apimLogger 'Microsoft.ApiManagement/service/loggers@2022-08-01' = {
  parent: apim
  name: 'app-insights-logger'
  properties: {
    loggerType: 'applicationInsights'
    credentials: {
      instrumentationKey: appInsights.properties.InstrumentationKey
    }
    isBuffered: true
    resourceId: appInsights.id
  }
}

// Named Value with Key Vault reference
resource namedValue 'Microsoft.ApiManagement/service/namedValues@2022-08-01' = {
  parent: apim
  name: 'backend-api-key'
  properties: {
    displayName: 'backend-api-key'
    secret: true
    keyVault: {
      secretIdentifier: 'https://${keyVaultName}.vault.azure.net/secrets/backend-api-key'
    }
  }
}
